// === Stroop-Daten strukturiert an SoSci Survey senden ===
var ds = this.options.datastore;
var allData = ds.data;

// Nur Stimulus-Screens filtern
// Practice: sender='Practice_Stimulus', Test: sender beginnt mit 'Test_Stimulus'
var trials = allData.filter(function(row) {
  return row.sender === 'Practice_Stimulus' || (row.sender && row.sender.indexOf('Test_Stimulus') === 0);
});

// Daten pro Spalte sammeln
var blocks = [];
var trialNrs = [];
var trialarten = [];
var accs = [];
var rts = [];
var stimuli = [];
var reaktionen = [];

trials.forEach(function(trial, i) {
  var block = (trial.sender === 'Practice_Stimulus') ? 'practice' : 'test';
  blocks.push(block);
  trialNrs.push(i + 1);
  trialarten.push(trial.congruency || '');
  accs.push(trial.correct === true ? 1 : 0);
  rts.push(Math.round(trial.duration || 0));
  stimuli.push(trial.word || '');
  reaktionen.push(trial.response || '');
});

// Strukturierte Daten per postMessage an SoSci-Seite senden
var msg = {
  type: 'labjs-data',
  task: 'stroop',
  K203_01: blocks.join(','),
  K203_02: trialNrs.join(','),
  K203_03: trialarten.join(','),
  K203_04: accs.join(','),
  K203_05: rts.join(','),
  K203_06: stimuli.join(','),
  K203_07: reaktionen.join(',')
};

try {
  window.parent.postMessage(msg, '*');
  console.log('Stroop: ' + trials.length + ' Trials per postMessage gesendet.');
} catch(e) {
  console.warn('Stroop postMessage fehlgeschlagen:', e);
}
